		_, _ = fmt.Fprintln(writer, "Available updates:")
		_, _ = fmt.Fprintln(writer, "Changes since last update:")
		return nil
	}

	// Handle dry-run mode
	if opts.DryRun {
		return displayDryRunResult(out, result, opts)
	}

	// Display success message
	_, _ = green.Fprintln(writer, "✅", result.Message)
